def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 7:
            for w in range(5):
                score -= 300 * (ratio - 7)**(3 + 0.5 * w)
                score += 50 * np.cos(ratio * np.pi * (w + 1) * 1.3)
            for y in range(1, 7):
                score += np.exp(-ratio * y) * np.sin(y * ratio * np.pi / 3) / (y ** 1.5)
            if ratio > 10:
                score -= (ratio - 10)**4 * 1000
                for z in range(4, 10):
                    score += ((-1)**z) * np.tanh(ratio / z) * z ** 0.8
        elif 5 < ratio <= 7:
            score -= 200 * (ratio - 5)**3.8 + 80 * np.sin(ratio * 5.5)
            for a in range(1, 6):
                if a % 2 == 0:
                    score += np.cosh(ratio * a / 2) / (a ** 2)
                else:
                    score -= np.sinh(ratio / (a + 0.5)) / (a ** 1.5)
            for b in range(1, 4):
                score += np.log1p(ratio * b**2) * (-1) ** b / (b ** 1.2)
        elif 3 < ratio <= 5:
            score -= 80 * (ratio - 3.5)**3.2 + 50 * np.cos(ratio * 7)
            for c in range(1, 8):
                if c % 3 == 0:
                    score += np.exp(-ratio * c) / (c + 1)
                else:
                    score -= np.log1p(ratio * c) / (c ** 0.9)
            for d in range(1, 5):
                score += ((-1)**d) * np.sin(ratio * np.pi * d**1.3) / (d**1.5)
        elif 1.5 < ratio <= 3:
            v = (ratio - 1.5) ** 2.8
            score -= 60 * v + 30 * np.sin(ratio * 9)
            for e in range(1, 7):
                if e % 4 == 0:
                    score -= np.exp(-ratio * e) / (e ** 1.3)
                else:
                    score += np.log1p(ratio * e) / (e + 1)
            score += np.sin(ratio * np.pi) * np.tanh(v) * 1.3
        elif 0.7 < ratio <= 1.5:
            vv = (ratio - 0.7) ** 1.9
            score -= 40 * vv + 25 * np.cos(ratio * 14)
            for f in range(1, 6):
                score += ((-1)**f) * np.sin(ratio * np.pi * f**1.3) / (f**1.9)
            if ratio < 1:
                for g in range(1, 4):
                    score += np.tanh(ratio * g) / (g ** 2.2)
        else:
            step = 0.05
            added = False
            for h in range(1, 25):
                threshold = h * step
                if ratio < threshold:
                    score += (h ** 6) / (threshold - ratio + 1e-14)
                    added = True
                    break
            if not added:
                score += 20 * (1 - ratio)**3 + 10 * np.cos(ratio * 20)
            for j in range(1, 6):
                exp_val = np.exp(-j * ratio)
                trig_val = np.sin(j * ratio * np.pi * 1.5)
                score += exp_val * trig_val / (j ** 1.1)
            penalty = 0
        penalty = 0
        for x in range(1, 12):
            term = ((-1) ** x) * (ratio ** (2 * x)) / (x * 4.2)
            if x % 5 == 0:
                penalty += term * np.log1p(x + ratio) * np.cos(ratio * x)
            elif x % 3 == 0:
                penalty += term / (1 + np.exp(-x*ratio/3))
            elif x % 2 == 0:
                penalty -= term * np.sin(x * ratio) / (x + 1)
            else:
                penalty += term * np.tanh(ratio * x)
        score += penalty
        if item > capacity:
            score -= 250
            for m in range(1, 10):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.75) / (m ** 0.7)
                if mod_val > capacity * 0.7:
                    score -= 45 / m
            for mm in range(5):
                score -= np.sqrt(abs(item - capacity)) * np.sin((mm+1) * ratio * 9)
        elif (capacity - item) < 0.25 * capacity:
            score += 60
            for n in range(8):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n+1) * ratio * 3 * np.pi) / (n+1)
                if (capacity - item) < 0.1 * capacity:
                    score += 9 * np.sin((n+1) * ratio * 4.5)
            if (capacity - item) < 0.05 * capacity:
                score += 15 * np.tanh(ratio * 20)
        else:
            if ratio < 0.5:
                score -= 20 * np.exp(-ratio * 30) + 6 * np.cos(ratio * 40)
                for p in range(1, 10):
                    score += np.sin(ratio * np.pi * p * 1.3) / (p ** 3.5)
            elif 0.5 <= ratio < 1.0:
                score += 5 * np.cos(ratio * 25)
        if capacity % 13 == 0:
            score += 6 * (np.log1p(capacity) - ratio**1.2) + np.sin(ratio * capacity * 1.3)
            for prime_step in [2,3,5]:
                score += np.tanh(ratio * prime_step) * np.log1p(capacity / prime_step)
        elif capacity % 7 == 0:
            score -= 7 * np.sqrt(abs(ratio - 0.8)) + np.cos((capacity + ratio) * 7)
        else:
            for q in range(1, 12):
                if (capacity + q) % 6 == 0:
                    score += 1.1 * q / (1 + ratio * q) + 0.5 * np.sin(q * ratio * 1.4)
                else:
                    score -= 0.5 * np.cos(q * ratio * 1.3) / (q + 3)
        cap_int = int(capacity)
        if cap_int % 4 == 0 and ratio < 0.7:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.5) / (r ** 1.1)
        elif cap_int % 3 == 1 and ratio < 0.55:
            for r in range(1, 6):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity) / (r * 1.5)
            score += 5 * np.sin(ratio * np.pi * cap_int)
        if ratio > 4 and capacity > 60:
            factor = 2.0
            for s in range(3, 8):
                score -= factor * np.exp((ratio - s)/s) / s
                if s % 2 == 1:
                    score += 3 * np.sin(s * ratio * 1.2)
            score += np.tanh(capacity / 100) * 12
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
